    14  async function generateCodeownersRawAudit(codeownersPath, outputPath) {
    15    try {
    16      await access(codeownersPath);
    17    } catch (error) {
    18      throw new Error(`CODEOWNERS file not found at: ${codeownersPath}`);
    19    }
    20
    21    return new Promise((resolve, reject) => {
    22      const outputStream = fs.createWriteStream(outputPath);
    23
    24      const child = spawn('yarn', ['github-codeowners', 'audit', '--output', 'jsonl'], {
    25        stdio: ['ignore', 'pipe', 'pipe'],
    26        cwd: process.cwd(),
    27        shell: true,
    28      });
    29
    30      let stderrData = '';
    31      child.stderr.on('data', (data) => {
    32        stderrData += data.toString();
    33      });
    34
    35      outputStream.on('error', (error) => {
    36        child.kill();
    37        reject(new Error(`Failed to write to output file: ${error.message}`));
    38      });
    39
    40      child.stdout.pipe(outputStream);
    41
    42      child.on('close', (code) => {
    43        outputStream.end();
    44        if (code === 0) {
    45          resolve();
    46        } else {
    47          const error = new Error(`github-codeowners process exited with code ${code}`);
    48          if (stderrData) {
    49            error.message += `\nStderr: ${stderrData.trim()}`;
    50          }
    51          reject(error);
    52        }
    53      });
    54
    55      child.on('error', (err) => {
    56        outputStream.end();
    57        if (err.code === 'ENOENT') {
    58          reject(new Error('yarn command not found. Please ensure yarn and github-codeowners are available'));
    59        } else {
    60          reject(err);
    61        }
    62      });
    63    });
    64  }
